// src/components/InventoryMonitoringPage/InventoryPage.tsx
import React, { useState, ChangeEvent, FormEvent } from "react";
import { useProducts, Product } from "../context/ProductContext";
import "./InventoryPage.css";

export default function InventoryPage() {
    const {
        products,
        addProduct,
        updateProduct,
        deleteProduct,
    } = useProducts();

    const [form, setForm] = useState<{
        name: string;
        category: string;
        stock: number;
        weight: number;
        price: number;
        description: string;
        date: string;
    }>({
        name: "",
        category: "",
        stock: 0,
        weight: 0,
        price: 0,
        description: "",
        // default to today
        date: new Date().toISOString().slice(0, 10),
    });

    const [editingId, setEditingId] = useState<number | null>(null);

    const handleInputChange = (e: ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setForm((prev) => ({
            ...prev,
            [name]:
                name === "stock" || name === "weight" || name === "price"
                    ? Number(value)
                    : value,
        }));
    };

    const handleSubmit = (e: FormEvent) => {
        e.preventDefault();
        const { name, category, stock, weight, price, description, date } = form;
        if (!name.trim() || !category.trim()) return;

        if (editingId === null) {
            // create new product, include createdAt
            addProduct({
                name,
                category,
                stock,
                weight,
                price,
                description,
                createdAt: date,
            });
        } else {
            // full update (including createdAt)
            updateProduct(editingId, {
                name,
                category,
                stock,
                weight,
                price,
                description,
                createdAt: date,
            });
            setEditingId(null);
        }

        // reset form
        setForm({
            name: "",
            category: "",
            stock: 0,
            weight: 0,
            price: 0,
            description: "",
            date: new Date().toISOString().slice(0, 10),
        });
    };

    const startEdit = (p: Product) => {
        setEditingId(p.id);
        setForm({
            name: p.name,
            category: p.category,
            stock: p.stock,
            weight: p.weight,
            price: p.price,
            description: p.description || "",
            date: p.createdAt.slice(0, 10),
        });
    };

    return (
        <div className="inventory-page-container">
            <h2>Inventory Management</h2>

            <form className="inventory-form" onSubmit={handleSubmit}>
                <input
                    name="name"
                    type="text"
                    placeholder="Ürün Adı"
                    value={form.name}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="category"
                    type="text"
                    placeholder="Kategori"
                    value={form.category}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="stock"
                    type="number"
                    placeholder="Stok Adedi"
                    value={form.stock}
                    onChange={handleInputChange}
                    min={0}
                    required
                />
                <input
                    name="weight"
                    type="number"
                    placeholder="Ağırlık (kg/l)"
                    value={form.weight}
                    onChange={handleInputChange}
                    min={0}
                    required
                />
                <input
                    name="price"
                    type="number"
                    placeholder="Fiyat"
                    step="0.01"
                    value={form.price}
                    onChange={handleInputChange}
                    min={0}
                    required
                />
                <input
                    name="description"
                    type="text"
                    placeholder="Açıklama"
                    value={form.description}
                    onChange={handleInputChange}
                />
                <input
                    name="date"
                    type="date"
                    value={form.date}
                    onChange={handleInputChange}
                    required
                />
                <button type="submit" className="submit-btn">
                    {editingId == null ? "Oluştur" : "Kaydet"}
                </button>
            </form>

            <div className="inventory-list">
                <h3>Current Inventory</h3>
                <ul>
                    {products.map((p) => (
                        <li key={p.id} className="item-row">
                            <div className="item-info">
                <span>
                  <strong>{p.name}</strong> — {p.category} — {p.stock} adet —{" "}
                    {p.weight} birim — ${p.price.toFixed(2)} — eklendi:{" "}
                    {p.createdAt.slice(0, 10)}
                </span>
                                <div className="item-actions">
                                    <button onClick={() => startEdit(p)}>Edit</button>
                                    <button onClick={() => deleteProduct(p.id)}>Delete</button>
                                </div>
                            </div>
                        </li>
                    ))}
                </ul>
            </div>
        </div>
    );
}
